(function() {
  if (document.readyState !== 'loading') {
    initAccordionJS();
  } else {
    document.addEventListener('DOMContentLoaded', initAccordionJS);
  }

  function initAccordionJS() {
    const botones = document.querySelectorAll("[selector='accordiones'] .btn-primary");
    botones.forEach(btn => {
      btn.removeEventListener('click', toggleOpenClass);
      btn.addEventListener('click', toggleOpenClass);
    });
  }

  function toggleOpenClass(evt) {
    this.classList.toggle("open");
  }

  return '';
  
})();

(function() {
  if (document.readyState !== 'loading') {
    initToggleAccordiones();
  } else {
    document.addEventListener('DOMContentLoaded', initToggleAccordiones);
  }

  function initToggleAccordiones() {
    const boton = document.querySelector("[selector='accordiones']");
    if (!boton) return;

    boton.removeEventListener("click", toggleInfoGeneral);
    boton.addEventListener("click", toggleInfoGeneral);
  }

  function toggleInfoGeneral() {
    const actual = window?.PM4?.variables?.acc_informacionGeneral;
    const nuevoValor = actual === "1" ? null : "1";
    window.PM4.setVariable("acc_informacionGeneral", nuevoValor);
  }

  return '';
})();

if (typeof this._initAccInfo === 'undefined') {
  this._initAccInfo = true;
  return "1";  // Solo la primera vez
}
return this.acc_informacionGeneral;

setTimeout(() => {
  const modalComponent = document.querySelector('[custom-css-selector="btn_preventivo"]');
  if (!modalComponent || !modalComponent.__vue__) return;

  const vueInstance = modalComponent.__vue__;

  vueInstance.$root.$on('bv::modal::show', (bvEvent, modalId) => {
    const modal = bvEvent.vueTarget;

    if (modalId === 'modal_preventivo') {
      modal.onOk = () => {
        const loader = document.getElementById('global-loader-overlay');
        const submitBtn = document.querySelector('button[name="btn_submit_real"]');

        // 🔍 Validar documentos adjuntos antes de hacer submit
        const tomador = this.grd_docsTomador || [];
        const asegurado = this.grd_docsAsegurado || [];

        const algunArchivo = [...tomador, ...asegurado].some(doc => {
          console.log(`📁 Revisando archivo: ${doc.grd_name_doc}`, doc.grd_file);
          return doc.grd_file !== null;
        });

        if (!algunArchivo) {
          console.warn("⛔ No hay documentos adjuntos en Tomador ni Asegurado.");
          vueInstance.$root.$bvModal.show('modal_documentos_faltantes');
          //alert("Debe adjuntar al menos un archivo en Documentos del Tomador o del Asegurado.");
          modal.hide();

          setTimeout(() => {
            if (loader) {
              loader.classList.remove("show");
              console.log("⛔ Loader ocultado porque no hay documentos.");
            }
          }, 350);

          return; // 🛑 No continuar con submit ni mostrar loader
        }

        // ✅ Si sí hay documentos, continuar con el flujo
        if (submitBtn) submitBtn.click();

        setTimeout(() => {
          const erroresVisibles = Array.from(document.querySelectorAll('.invalid-feedback'))
            .filter(div => {
              const visible = div.offsetParent !== null;
              const mensaje = div.textContent.trim().toLowerCase();
              return visible && (
                mensaje.includes("campo requerido") ||
                mensaje.includes("debe ser igual o después de")
              );
            });

          console.log("🔍 Errores visibles encontrados:", erroresVisibles.length);

          if (erroresVisibles.length === 0 && loader) {
            loader.classList.add('show');
            console.log("✅ Mostrando loader: no hay errores visibles y hay documentos");
          } else {
            console.log("❌ No se muestra loader: errores visibles encontrados");
          }
        }, 300);

        modal.hide();
      };
    }
  });
}, 500);

try {
  const pais = this.frm_pais;
  let lista = [];

  console.debug("🌎 País seleccionado:", pais);

  if (pais === "CO") {
    lista = this.frm_docsList_tomador_co;
  } else if (pais === "MX") {
    lista = this.frm_docsList_tomador_mx;
  } else if (pais === "CL") {
    lista = this.frm_docsList_tomador_cl;
  } else {
    console.debug("🚫 País no válido o sin lista de documentos");
    return [];
  }

  if (!Array.isArray(lista)) {
    console.debug("⚠️ La lista de documentos no es un array:", lista);
    return [];
  }

  const existentes = this.grd_docsTomador || [];
  const frm_decision_bandera = this.frm_decision_bandera;

  console.debug("📄 Lista base de documentos:", lista);
  console.debug("📂 Datos existentes en grd_docsTomador:", existentes);

  const resultado = lista.map((texto, index) => {
    const nombreDocumento = `${index + 1}. ${texto}`;
    const previo = existentes.find(doc => doc.grd_index === index);

    const doc = {
      grd_index: index,
      grd_name_doc: nombreDocumento,
      grd_check: previo?.grd_check ?? false,
      grd_file: previo?.grd_file ?? null,
      grd_vista: previo?.grd_vista ?? null,
      grd_decision_bandera: frm_decision_bandera,
      grd_seleccion: previo?.grd_seleccion ?? null,
      grd_observacion: previo?.grd_observacion ?? null
    };

    console.debug(`📌 Documento [${index}] generado:`, doc);
    return doc;
  });

  console.debug("✅ Resultado final a retornar:", resultado);
  return resultado;
} catch (e) {
  console.log("⚠️ Error generando lista dinámica:", e);
  return [];
}

try {
  const pais = this.frm_pais;
  let lista = [];

  if (pais === "CO") {
    lista = this.frm_docsList_asegurado_co;
  } else if (pais === "MX") {
    lista = this.frm_docsList_asegurado_mx;
  } else if (pais === "CL") {
    lista = this.frm_docsList_asegurado_cl;
  } else {
    return [];
  }

  if (!Array.isArray(lista)) {
    return [];
  }

  const existentes = this.grd_docsAsegurado || [];
  const frm_decision_bandera = this.frm_decision_bandera;

  const resultado = lista.map((texto, index) => {
    const nombre = `${index + 1}. ${texto}`;
    const previo = existentes.find(doc => doc.grd_name_doc === nombre);

    return {
      grd_index: index,
      grd_name_doc: nombre,
      grd_check: previo ? previo.grd_check : false,
      grd_file: previo ? previo.grd_file : null,
      grd_vista: previo ? previo.grd_vista : null,
      grd_decision_bandera: frm_decision_bandera
    };
  });

  return resultado;
} catch (e) {
  console.log("⚠️ Error generando lista dinámica:", e);
  return [];
}

